    private BufferedReader br(String s) {
        return new BufferedReader(new StringReader(s));
    }

    @Test
    public void test_createPlayer_human_returns_TextPlayer() throws IOException {
        Board<Character> b = new BattleShipBoard<>(10, 20, 'X');
        AbstractShipFactory<Character> f = new V2ShipFactory();
        ByteArrayOutputStream bytes = new ByteArrayOutputStream();
        PrintStream out = new PrintStream(bytes);

        Player p = App.createPlayer("A", b, br("h\n"), out, f, 10, 20);

        assertTrue(p instanceof TextPlayer);
        assertEquals("A", p.getName());
        assertSame(b, p.getBoard());
    }

