    @Test
    public void test_createPlayer_reprompts_on_invalid_then_accepts() throws IOException {
        Board<Character> b = new BattleShipBoard<>(10, 20, 'X');
        AbstractShipFactory<Character> f = new V2ShipFactory();
        ByteArrayOutputStream bytes = new ByteArrayOutputStream();
        PrintStream out = new PrintStream(bytes);

        Player p = App.createPlayer("A", b, br("wat\nh\n"), out, f, 10, 20);

        assertTrue(p instanceof TextPlayer);
        String s = bytes.toString();
        assertTrue(s.contains("Is Player A a human or computer? (h/c)"));
        assertTrue(s.contains("Please enter 'h' or 'c'"));
    }

